import React, { useState } from "react";
import "./RegisterCourse.css";
import Navbar from "../components/navbar";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function RegisterCourse() {

  const [studentId, setStudentId] = useState("");
  const [courseId, setCourseId] = useState("");
  const [courseCode, setCourseCode] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    const token = localStorage.getItem("token");
    console.log("Token from localStorage:", token);

    if (!token) {
      alert("You are not logged in!");
      return;
    }

    if (!studentId || !courseId || !courseCode) {
      alert("All fields are required");
      return;
    }

    try {
      const res = await axios.post(
        "http://localhost:5000/registercourse",
        { studentId, courseId, courseCode },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      alert("✅ " + res.data.message);

      // Reset form
      setStudentId("");
      setCourseId("");
      setCourseCode("");
      navigate("")
    } catch (err) {
      console.error("Error registering course:", err.response?.data || err.message);
      alert(err.response?.data?.message || "Error registering course");
    }
  };

  return (
    <>
      <Navbar />
      <form className="register-form" onSubmit={handleSubmit}>
        <h2>Register Course</h2>

        <label>Student ID</label>
        <input
          type="text"
          value={studentId}
          onChange={(e) => setStudentId(e.target.value)}
          required
        />

        <label>Course ID</label>
        <input
          type="text"
          value={courseId}
          onChange={(e) => setCourseId(e.target.value)}
          required
        />

        <label>Course Code</label>
        <input
          type="text"
          value={courseCode}
          onChange={(e) => setCourseCode(e.target.value)}
          required
        />

        <button type="submit">Register</button>
      </form>
    </>
  );
}

export default RegisterCourse;
